// // This module implements a 9-bit shift register that shifts its content to the right on each negative edge of the clock and resets to all ones when the reset signal is low.
module shift_register_8bit(
    input clk,
    input reset,
    input data_in,
    output reg [7:0] data_out
);

always @(posedge clk or posedge reset) begin
    if (reset)
        data_out <= 8'b0;
    else
        data_out <= {data_out[6:0], data_in};
end

endmodule
